"use strict";(globalThis.webpackChunkdocusaurus_site=globalThis.webpackChunkdocusaurus_site||[]).push([[9813],{6860(e){e.exports=JSON.parse('[{"slug":"milky1","title":"Milky Way in Sai Kung (Untracked)","date":"2025-09","year":null,"featuredRank":1,"thumb":"/img/gallery/_gen/milky1-thumb.jpg","image":"/img/gallery/_gen/milky1-full.jpg","aspect":1.3819987959060807,"srcAbs":"/mnt/ssd/eason_project/website_raw/gallery/img/milky1.jpg","source":"@site/gallery/milky1.mdx","sourceFilePath":"gallery/milky1.mdx","_content":"\\nFirst time trying the Milky Way. Stock EOS R8, cheap RF 24-50 f4.5-6.3 IS STM @ 24mm f4.5, 100x 8s ISO 3200. Processed in Siril & Darktable.\\n\\nTook darks/biases/flats but didn\'t use it because lens vignetting and distortion are so bad that the four corners are completely black. I need to load the camera raw into darktable for lens correction and directly use the processed linear images for stacking, so I didn\'t apply the calibration frames. Bortle 5 but closer to bortle 6 due to the extremely bright blue fishing boat lights nearby, I can\'t even see the milky way from the raw camera frames. But nevertheless it is a good first try."},{"slug":"orion1","title":"M42 Orion Nebula","date":"2026-02","year":null,"featuredRank":1,"thumb":"/img/gallery/_gen/orion1-thumb.jpg","image":"/img/gallery/_gen/orion1-full.jpg","aspect":1.509763082530591,"srcAbs":"/mnt/ssd/eason_project/website_raw/gallery/img/orion1.jpg","source":"@site/gallery/orion1.mdx","sourceFilePath":"gallery/orion1.mdx","_content":"\\nSecond time trying the M42 Orion Nebula, Horsehead, and Flame Nebula. Also the first time using the newly bought OG Tracker v2. Couldn\'t see Polaris due to light pollution, so polar aligned by pressing my phone onto the tracker and eyeballed the position of Polaris until it\'s at the centre of my phone screen.\\n\\nStock EOS R8, RF 70-200 f4 L IS USM @ 200mm f4, 49x 45s ISO 800. Processed in PixInsight.\\n\\nPixInsight brought out so much detail compared to Siril with Darktable. Taken in Bortle 4/5."},{"slug":"rosette1","title":"Caldwell 49 Rosette Nebula","date":"2026-02","year":null,"featuredRank":1,"thumb":"/img/gallery/_gen/rosette1-thumb.jpg","image":"/img/gallery/_gen/rosette1-full.jpg","aspect":1.6125323368784132,"srcAbs":"/mnt/ssd/eason_project/website_raw/gallery/img/rosette1.jpg","source":"@site/gallery/rosette1.mdx","sourceFilePath":"gallery/rosette1.mdx","_content":"\\nFirst time trying the C49 Rosette Nebula. This time I was able to see Polaris, so I polar aligned with the laser, which turns out can do 20s subs pretty fine.\\n\\nStock EOS R8, RF 70-200 f4 L IS USM @ 200mm f4, 300x 20s ISO 1600. Processed in PixInsight. First time using PixInsight, it was honestly quite easy to learn, and this is the second edit, which I used a masked stretch to preserve blue in the centre, but it makes it much brighter. I would prefer having more blue/cyan in the centre more though.\\n\\nPixInsight brought out so much detail compared to Siril with Darktable. Taken in Bortle 4/5."},{"slug":"andromeda1","title":"M31 in Sai Kung (Untracked)","date":"2025-11","year":null,"featuredRank":1,"thumb":"/img/gallery/_gen/andromeda1-thumb.png","image":"/img/gallery/_gen/andromeda1-full.png","aspect":1.334154756037457,"srcAbs":"/mnt/ssd/eason_project/website_raw/gallery/img/andromeda1.png","source":"@site/gallery/andromeda1.mdx","sourceFilePath":"gallery/andromeda1.mdx","_content":"\\nSecond time trying Andromeda, untracked. Stock EOS R8, RF 70-200 f4 L IS USM @ 200mm f4, 450x 2.5s ISO 6400. Processed in PixInsight.\\n\\nEyeballed the focus... will get a tracker and bahtinov mask soon. PixInsight brought out so much detail compared to Siril. Taken in Bortle 5."},{"slug":"pleiades1","title":"M45 Pleiades in Sai Kung (Untracked)","date":"2025-11","year":null,"featuredRank":1,"thumb":"/img/gallery/_gen/pleiades1-thumb.jpg","image":"/img/gallery/_gen/pleiades1-full.jpg","aspect":1.5696278511404562,"srcAbs":"/mnt/ssd/eason_project/website_raw/gallery/img/pleiades1.jpg","source":"@site/gallery/pleiades1.mdx","sourceFilePath":"gallery/pleiades1.mdx","_content":"\\nFirst time trying M45 Pleiades, untracked. Stock EOS R8, RF 70-200 f4 L IS USM @ 200mm f4, 350x 2.5s ISO 6400. Processed in PixInsight.\\n\\nEyeballed the focus... will get a tracker and bahtinov mask soon. PixInsight brought out so much detail compared to Siril. Taken in Bortle 5."},{"slug":"ngc7000-1","title":"NGC7000 in backyard (Untracked)","date":"2025-09","year":null,"featuredRank":1,"thumb":"/img/gallery/_gen/ngc7000-1-thumb.jpg","image":"/img/gallery/_gen/ngc7000-1-full.jpg","aspect":1.5700934579439252,"srcAbs":"/mnt/ssd/eason_project/website_raw/gallery/img/ngc7000-1.jpg","source":"@site/gallery/ngc7000-1.mdx","sourceFilePath":"gallery/ngc7000-1.mdx","_content":"\\nSecond time trying NGC7000 North America Nebula, untracked. Stock EOS R8, RF 70-200 f4 L IS USM @ 200mm f4, 1000x 2s ISO 3200. Processed in PixInsight.\\n\\nEyeballed the focus... will get a tracker and bahtinov mask soon. PixInsight brought out so much detail compared to Siril, and NoiseXterminator was a life saver. Taken in Bortle 7/8."},{"slug":"sharp-peak-blue-sky","title":"Mountain and Blue Sky","date":"2025-11","year":null,"featuredRank":2,"thumb":"/img/gallery/_gen/sharp-peak-blue-sky-thumb.jpg","image":"/img/gallery/_gen/sharp-peak-blue-sky-full.jpg","aspect":0.6666666666666666,"srcAbs":"/mnt/ssd/eason_project/website_raw/gallery/img/sharp-peak-blue-sky.jpg","source":"@site/gallery/sharp-peak-blue-sky.mdx","sourceFilePath":"gallery/sharp-peak-blue-sky.mdx","_content":"\\nTook this photo during the exhausting climb of Sharp Peak in Hong Kong. The sky was so blue, contrasting the dark gree mountains, which created this beautiful photo.\\n\\nEOS R8, RF 24-50 f4.5-6.3 IS STM @ 28mm f5, 1/640s, ISO 100."},{"slug":"sharp-peak-sunset","title":"Sunset Over the Mountains","date":"2025-11","year":null,"featuredRank":2,"thumb":"/img/gallery/_gen/sharp-peak-sunset-thumb.jpg","image":"/img/gallery/_gen/sharp-peak-sunset-full.jpg","aspect":1.5,"srcAbs":"/mnt/ssd/eason_project/website_raw/gallery/img/sharp-peak-sunset.jpg","source":"@site/gallery/sharp-peak-sunset.mdx","sourceFilePath":"gallery/sharp-peak-sunset.mdx","_content":"\\nAfter an exhausting climb, I got to see this beautiful sunset on top of Sharp Peak in Hong Kong. Still one of the best sunset I\'ve ever seen.\\n\\nEOS R8, RF 24-50 f4.5-6.3 IS STM @ 24mm f4.5, 1/400s, ISO 800."}]')}}]);